 58→  const [heatmap, setHeatmap] = useState<HeatLevel[][]>([
 59→    ['Low', 'Low', 'Low', 'Low'],
 60→    ['Low', 'Low', 'Low', 'Low'],
 61→    ['Low', 'Low', 'Low', 'Low']
 62→  ]);
 63→  const t = (en: string, fr: string) => (language === 'fr' ? fr : en);
 64→
 65→  const categorylabel = (category: SubmissionCategory): string => {
 66→    return categoryPluralLabel(category, language);
 67→  };
 68→
 69→  useEffect(() => {
 70→    if (!adminMode) return;
