 79→  useEffect(() => {
 80→    const loadLeaderboard = async () => {
 81→      try {
 82→        setIsLoadingLeaderboard(true);
 83→        const data = await apiJson<LeaderboardEntry[]>('/api/leaderboard');
 84→        setLeaderboard(Array.isArray(data) ? data : []);
 85→      } catch {
