 94→
 95→  useEffect(() => {
 96→    if (!adminMode) return;
 97→    const loadAdminAnalytics = async () => {
 98→      try {
 99→        setIsLoadingAdminData(true);
100→        const scope = normalizeMapScope('global', true);
101→
102→        const pointParams = new URLSearchParams();
103→        if (scope !== 'bonamoussadi') pointParams.set('scope', scope);
104→        const pointsPath = pointParams.size > 0 ? `/api/submissions?${pointParams.toString()}` : '/api/submissions';
105→
106→        const eventParams = new URLSearchParams({ view: 'events' });
107→        if (scope !== 'bonamoussadi') eventParams.set('scope', scope);
108→        const eventsPath = `/api/submissions?${eventParams.toString()}`;
109→
110→        const [points, events] = await Promise.all([
111→          apiJson<ProjectedPoint[]>(pointsPath),
112→          apiJson<PointEvent[]>(eventsPath)
113→        ]);
114→
115→        const safePoints = Array.isArray(points) ? points : [];
116→        const safeEvents = Array.isArray(events) ? events : [];
117→
118→        const completed = safePoints.filter((point) => Array.isArray(point.gaps) && point.gaps.length === 0).length;
119→        const completion = safePoints.length > 0 ? Math.round((completed / safePoints.length) * 100) : 0;
120→        setCompletionRate(completion);
121→
122→        const now = Date.now();
123→        const activeWindowMs = 30 * 24 * 60 * 60 * 1000;
124→        const activeUsers = new Set(
125→          safeEvents
126→            .filter((event) => {
127→              const createdAt = new Date(event.createdAt).getTime();
128→              return Number.isFinite(createdAt) && now - createdAt <= activeWindowMs;
129→            })
130→            .map((event) => event.userId)
131→            .filter((userId) => typeof userId === 'string' && userId.trim().length > 0)
132→        );
133→        setActiveContributors(activeUsers.size);
134→
135→        const categoryCounts: Record<string, number> = {};
136→        for (const id of VERTICAL_IDS) categoryCounts[id] = 0;
137→        for (const event of safeEvents) {
138→          if (event.category in categoryCounts) categoryCounts[event.category] += 1;
139→        }
140→        setCategoryData(
141→          VERTICAL_IDS
142→            .filter((id) => (categoryCounts[id] ?? 0) > 0)
143→            .map((id) => ({ name: categorylabel(id as SubmissionCategory), value: categoryCounts[id], color: VERTICALS[id].color }))
144→        );
145→
146→        const categories = VERTICAL_IDS;
147→        const bucketsPerCategory = categories.map(() => [0, 0, 0, 0]);
148→        const heatWindowMs = 24 * 60 * 60 * 1000;
149→        for (const event of safeEvents) {
150→          const timestamp = new Date(event.createdAt).getTime();
151→          if (!Number.isFinite(timestamp) || now - timestamp > heatWindowMs || timestamp > now) continue;
152→          const categoryIndex = categories.indexOf(event.category);
153→          if (categoryIndex === -1) continue;
154→          const bucketIndex = Math.max(0, Math.min(3, Math.floor(new Date(timestamp).getHours() / 6)));
155→          bucketsPerCategory[categoryIndex][bucketIndex] += 1;
156→        }
157→
158→        const maxValue = Math.max(...bucketsPerCategory.flat(), 0);
159→        const toHeatLevel = (value: number): HeatLevel => {
160→          if (maxValue <= 0 || value <= 0) return 'Low';
161→          const ratio = value / maxValue;
162→          if (ratio >= 0.67) return 'High';
163→          if (ratio >= 0.34) return 'Medium';
164→          return 'Low';
165→        };
166→
167→        setHeatmap(
168→          bucketsPerCategory.map((row) => row.map((value) => toHeatLevel(value)))
169→        );
170→      } catch {
171→        setCompletionRate(0);
172→        setActiveContributors(0);
173→        setCategoryData([]);
174→        setHeatmap(VERTICAL_IDS.map(() => ['Low', 'Low', 'Low', 'Low'] as HeatLevel[]));
175→      } finally {
