230→export async function registerWithCredentials(identifier: string, password: string, name?: string): Promise<void> {
231→  const normalizedIdentifier = normalizeIdentifier(identifier)?.value ?? identifier.trim();
232→  const response = await apiFetch("/api/auth/register", {
233→    method: "POST",
234→    headers: { "Content-Type": "application/json" },
235→    body: JSON.stringify({ identifier: normalizedIdentifier, email: normalizedIdentifier, password, name }),
236→  });
237→
238→  if (!response.ok) {
239→    const { message, code } = await extractResponseErrorPayload(response, DEFAULT_SIGN_UP_ERROR);
240→    if (response.status === 409) {
241→      throw new AuthClientError("registration_conflict", message);
242→    }
243→    if (response.status === 400) {
244→      throw new AuthClientError("validation_error", message);
245→    }
246→    if (response.status === 503 && code === "storage_unavailable") {
247→      throw new AuthClientError("storage_unavailable", message, { retryable: true });
248→    }
249→    const retryable = response.status >= 500;
250→    throw new AuthClientError(retryable ? "auth_unavailable" : "request_error", message, { retryable });
251→  }
252→}
