 92→async function withAbsoluteUrl(request: Request): Promise<Request> {
 93→  try {
 94→    // eslint-disable-next-line no-new
 95→    new URL(request.url);
 96→    return request;
 97→  } catch {
 98→    const base = process.env.AUTH_URL ?? process.env.NEXTAUTH_URL ?? "http://localhost:3000";
 99→    const url = new URL(request.url || "/", base);
100→    const method = request.method ?? "GET";
101→    const init: RequestInit = {
102→      method,
103→      headers: request.headers,
104→      redirect: request.redirect,
105→    };
106→    if (method !== "GET" && method !== "HEAD") {
107→      init.body = await request.arrayBuffer();
108→    }
109→    return new Request(url, init);
110→  }
111→}
