113→export default async function handler(request: Request): Promise<Response> {
114→  try {
115→    const normalizedRequest = await withAbsoluteUrl(request);
116→    return await Auth(normalizedRequest, {
117→      providers,
118→      secret: authSecret,
119→      session: { strategy: "jwt" },
120→      trustHost: true,
121→      basePath: "/api/auth",
122→      cookies: {
123→        sessionToken: {
124→          name: getSessionCookieName(),
125→          options: {
126→            httpOnly: true,
127→            sameSite: "lax",
128→            path: "/",
129→            secure: isSecureRequest(),
130→          },
131→        },
132→      },
133→      callbacks: {
134→        async signIn({ user, account }) {
135→          const email = normalizeEmail(user?.email);
136→          const adminEmail = normalizeEmail(process.env.ADMIN_EMAIL);
137→          const isAdminAccount = Boolean(email && adminEmail && email === adminEmail);
138→          const provider = account?.provider ?? "unknown";
139→
140→          if (!email) return true;
141→          if (!isAdminAccount && account?.provider !== "google") return true;
142→
143→          try {
144→            if (isAdminAccount) {
145→              const existing = await getUserProfile(email);
146→              if (existing) {
147→                let shouldUpdate = false;
148→                if (!existing.isAdmin) {
149→                  existing.isAdmin = true;
150→                  shouldUpdate = true;
151→                }
152→                if (existing.mapScope !== "global") {
153→                  existing.mapScope = "global";
154→                  shouldUpdate = true;
155→                }
156→                if (shouldUpdate) {
157→                  await upsertUserProfile(email, existing);
158→                }
159→              } else {
160→                const profile: UserProfile = {
161→                  id: email,
162→                  name: user?.name ?? inferDefaultDisplayName(email),
163→                  email,
164→                  phone: null,
165→                  image: user?.image ?? "",
166→                  occupation: "",
167→                  XP: 0,
168→                  isAdmin: true,
169→                  mapScope: "global",
170→                };
171→                await upsertUserProfile(email, profile);
172→              }
173→              return true;
174→            }
175→
176→            const existing = await getUserProfile(email);
177→            if (existing) {
178→              if (!existing.mapScope) {
179→                existing.mapScope = "bonamoussadi";
180→                await upsertUserProfile(email, existing);
181→              }
182→              return true;
183→            }
184→
185→            const profile: UserProfile = {
186→              id: email,
187→              name: user?.name ?? inferDefaultDisplayName(email),
188→              email,
189→              phone: null,
190→              image: user?.image ?? "",
191→              occupation: "",
192→              XP: 0,
193→              mapScope: "bonamoussadi",
194→            };
195→            await upsertUserProfile(email, profile);
196→            return true;
197→          } catch (error) {
198→            // Do not block OAuth sign-in if profile sync fails.
199→            if (isStorageUnavailableError(error)) {
200→              console.error("[auth] profile sync skipped: storage unavailable", { email, provider });
201→              return true;
202→            }
203→            console.error("[auth] profile sync failed during sign-in", {
204→              email,
205→              provider,
206→              message: error instanceof Error ? error.message : String(error),
207→            });
208→            return true;
209→          }
210→        },
211→        async jwt({ token, user }) {
212→          const adminEmail = normalizeEmail(process.env.ADMIN_EMAIL);
213→          const email = normalizeEmail(user?.email ?? token?.email);
214→          if (adminEmail && email && adminEmail === email) {
215→            (token as { isAdmin?: boolean }).isAdmin = true;
216→          } else {
217→            (token as { isAdmin?: boolean }).isAdmin = false;
218→          }
219→          if (email) {
220→            (token as { uid?: string }).uid = email.trim();
221→          } else if (user) {
222→            const id = (user as { id?: string }).id ?? user.email;
223→            if (id) (token as { uid?: string }).uid = id;
224→          }
225→          return token;
226→        },
227→        async session({ session, token }) {
228→          if (session.user && token?.uid) {
229→            (session.user as { id?: string }).id = token.uid as string;
230→          }
231→          if (session.user && (token as { isAdmin?: boolean })?.isAdmin !== undefined) {
232→            (session.user as { isAdmin?: boolean }).isAdmin = Boolean((token as { isAdmin?: boolean }).isAdmin);
233→          }
234→          return session;
235→        },
236→      },
237→    });
238→  } catch (error) {
239→    if (isStorageUnavailableError(error)) {
240→      return errorResponse("Storage service temporarily unavailable", 503, { code: "storage_unavailable" });
241→    }
242→    throw error;
243→  }
244→}
