14→export async function POST(request: Request): Promise<Response> {
15→  let body: RegisterBody;
16→  try {
17→    body = (await request.json()) as RegisterBody;
18→  } catch {
19→    return errorResponse("Invalid JSON body", 400);
20→  }
21→
22→  const rawIdentifier = body?.identifier ?? body?.email;
23→  const normalizedIdentifier = normalizeIdentifier(rawIdentifier);
24→  const password = body?.password;
25→  const name = body?.name?.trim() ?? "";
26→
27→  if (!normalizedIdentifier || !password) {
28→    return errorResponse("Phone/email and password are required", 400);
29→  }
30→
31→  if (password.length < 8) {
32→    return errorResponse("Password must be at least 8 characters", 400);
33→  }
34→
35→  try {
36→    const identifier = normalizedIdentifier.value;
37→    const existing = await getUserProfile(identifier);
38→    if (existing) {
39→      return errorResponse("User already exists", 409);
40→    }
41→
42→    const profile: UserProfile = {
43→      id: identifier,
44→      name: name || inferDefaultDisplayName(identifier),
45→      email: normalizedIdentifier.type === "email" ? identifier : null,
46→      phone: normalizedIdentifier.type === "phone" ? identifier : null,
47→      image: "",
48→      occupation: "",
49→      XP: 0,
50→      passwordHash: bcrypt.hashSync(password, 10),
