 10→function resolveDriver(): StorageDriver {
 11→  const configured = process.env.DATA_STORE_DRIVER?.trim().toLowerCase();
 12→  if (configured === "edge") return "edge";
 13→  if (configured === "postgres") return "postgres";
 14→  if (process.env.POSTGRES_URL || process.env.POSTGRES_PRISMA_URL || process.env.POSTGRES_URL_NON_POOLING) {
 15→    return "postgres";
 16→  }
 17→  return "edge";
 18→}
 19→
 20→function fallbackEnabled(): boolean {
 21→  return process.env.DATA_READ_FALLBACK_EDGE === "true";
 22→}
 23→
 24→function getPrimaryStore(): StorageStore {
 25→  return resolveDriver() === "postgres" ? postgresStore : edgeConfigStore;
 26→}
 27→
 28→function shouldUseFallback(): boolean {
 29→  return resolveDriver() === "postgres" && fallbackEnabled();
 30→}
 31→
 32→function mergeEvents(primaryEvents: PointEvent[], fallbackEvents: PointEvent[]): PointEvent[] {
 33→  if (!fallbackEvents.length) return primaryEvents;
 34→  if (!primaryEvents.length) return fallbackEvents;
 35→
 36→  const deduped = new Map<string, PointEvent>();
 37→  for (const event of primaryEvents) deduped.set(event.id, event);
 38→  for (const event of fallbackEvents) {
 39→    if (!deduped.has(event.id)) deduped.set(event.id, event);
 40→  }
 41→
 42→  return Array.from(deduped.values()).sort((a, b) => new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime());
 43→}
