import { apiFetch, apiJson, buildUrl } from "./api";
import { normalizeIdentifier } from "../shared/identifier";
import { looksLikeHtml, sanitizeErrorMessage } from "./errorUtils";

export interface AuthSession {
  user?: {
    id?: string;
    name?: string | null;
    email?: string | null;
    image?: string | null;
    isAdmin?: boolean;
  };
  expires?: string;
}

export interface SignInWithCredentialsOptions {
  maxAttempts?: number;
  retryDelayMs?: number;
}

export type AuthClientErrorCode =
  | "invalid_credentials"
  | "callback_error"
  | "configuration_error"
  | "access_denied"
  | "auth_unavailable"
  | "storage_unavailable"
  | "registration_conflict"
  | "validation_error"
  | "request_error"
  | "unknown_error";

export class AuthClientError extends Error {
  code: AuthClientErrorCode;
  retryable: boolean;

  constructor(
    code: AuthClientErrorCode,
    message: string,
    options: { retryable?: boolean; cause?: unknown } = {}
  ) {
    super(message);
    this.name = "AuthClientError";
    this.code = code;
    this.retryable = Boolean(options.retryable);
    if (options.cause !== undefined) {
      (this as Error & { cause?: unknown }).cause = options.cause;
    }
  }
}

type AuthRedirectPayload = {
  url?: unknown;
};

const DEFAULT_SIGN_IN_ERROR = "Unable to sign in. Please try again.";
const DEFAULT_SIGN_OUT_ERROR = "Unable to sign out";
const DEFAULT_SIGN_UP_ERROR = "Unable to create account";

function delay(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

function normalizeAttempts(value: number | undefined): number {
  if (!Number.isFinite(value)) return 1;
  return Math.max(1, Math.floor(value as number));
}

function normalizeDelayMs(value: number | undefined): number {
  if (!Number.isFinite(value)) return 500;
  return Math.max(0, Math.floor(value as number));
}


async function safeReadJson<T>(response: Response): Promise<T | null> {
  try {
    return (await response.json()) as T;
  } catch {
    return null;
  }
}

type ApiErrorPayload = {
  message: string;
  code?: string;
};

async function extractResponseErrorPayload(response: Response, fallback: string): Promise<ApiErrorPayload> {
  const contentType = response.headers.get("content-type")?.toLowerCase() ?? "";
  if (contentType.includes("application/json")) {
    const payload = await safeReadJson<{ error?: unknown; message?: unknown; code?: unknown }>(response);
    if (payload) {
      const message = sanitizeErrorMessage(payload.error ?? payload.message, fallback);
      const code = typeof payload.code === "string" && payload.code.trim() ? payload.code.trim() : undefined;
      return { message, code };
    }
    return { message: fallback };
  }
  const text = await response.text().catch(() => "");
  return { message: sanitizeErrorMessage(text, fallback) };
}

function mapAuthJsError(errorType: string | null, errorCode: string | null): AuthClientError {
  switch (errorType) {
    case "CredentialsSignin":
      return new AuthClientError("invalid_credentials", "Invalid phone/email or password.", { retryable: true });
    case "Callback":
    case "CallbackRouteError":
      return new AuthClientError("callback_error", DEFAULT_SIGN_IN_ERROR, { retryable: true });
    case "Configuration":
      return new AuthClientError("configuration_error", DEFAULT_SIGN_IN_ERROR, { retryable: true });
    case "AccessDenied":
      return new AuthClientError("access_denied", "Access denied for this account.");
    default:
      if (errorCode === "credentials") {
        return new AuthClientError("invalid_credentials", "Invalid phone/email or password.", { retryable: true });
      }
      return new AuthClientError("unknown_error", DEFAULT_SIGN_IN_ERROR, { retryable: true });
  }
}

function toAuthClientError(error: unknown, fallback: string): AuthClientError {
  if (error instanceof AuthClientError) return error;
  if (error instanceof Error) {
    return new AuthClientError("unknown_error", sanitizeErrorMessage(error.message, fallback), { cause: error });
  }
  return new AuthClientError("unknown_error", fallback);
}

async function getCsrfToken(): Promise<string> {
  const data = await apiJson<{ csrfToken: string }>("/api/auth/csrf");
  return data.csrfToken;
}

export async function getSession(): Promise<AuthSession | null> {
  try {
    const session = await apiJson<AuthSession>("/api/auth/session");
    if (session?.user) return session;
    return null;
  } catch {
    return null;
  }
}

async function signInWithCredentialsOnce(identifier: string, password: string): Promise<void> {
  const normalizedIdentifier = normalizeIdentifier(identifier)?.value ?? identifier.trim();
  const csrfToken = await getCsrfToken();
  const body = new URLSearchParams();
  body.set("csrfToken", csrfToken);
  body.set("identifier", normalizedIdentifier);
  body.set("email", normalizedIdentifier);
  body.set("password", password);
  body.set("callbackUrl", window.location.origin);
  body.set("json", "true");

  const response = await apiFetch("/api/auth/callback/credentials", {
    method: "POST",
    headers: {
      "Content-Type": "application/x-www-form-urlencoded",
      "X-Auth-Return-Redirect": "1",
    },
    body,
  });

  if (!response.ok) {
    const { message } = await extractResponseErrorPayload(response, DEFAULT_SIGN_IN_ERROR);
    const retryable = response.status >= 500;
    throw new AuthClientError(retryable ? "auth_unavailable" : "request_error", message, { retryable });
  }

  const payload = await safeReadJson<AuthRedirectPayload>(response);
  if (!payload || typeof payload.url !== "string") {
    throw new AuthClientError("unknown_error", DEFAULT_SIGN_IN_ERROR, { retryable: true });
  }

  let url: URL;
  try {
    url = new URL(payload.url, window.location.origin);
  } catch {
    throw new AuthClientError("unknown_error", DEFAULT_SIGN_IN_ERROR, { retryable: true });
  }

  const errorType = url.searchParams.get("error");
  const errorCode = url.searchParams.get("code");
  if (errorType || errorCode) {
    throw mapAuthJsError(errorType, errorCode);
  }
}

export async function signInWithCredentials(
  identifier: string,
  password: string,
  options: SignInWithCredentialsOptions = {}
): Promise<void> {
  const maxAttempts = normalizeAttempts(options.maxAttempts);
  const retryDelayMs = normalizeDelayMs(options.retryDelayMs);

  for (let attempt = 1; attempt <= maxAttempts; attempt += 1) {
    try {
      await signInWithCredentialsOnce(identifier, password);
      return;
    } catch (error) {
      const authError = toAuthClientError(error, DEFAULT_SIGN_IN_ERROR);
      const shouldRetry = authError.retryable && attempt < maxAttempts;
      if (!shouldRetry) throw authError;
      await delay(retryDelayMs);
    }
  }
}

export async function signOut(): Promise<void> {
  const csrfToken = await getCsrfToken();
  const body = new URLSearchParams();
  body.set("csrfToken", csrfToken);
  body.set("callbackUrl", window.location.origin);
  body.set("json", "true");

  const response = await apiFetch("/api/auth/signout", {
    method: "POST",
    headers: { "Content-Type": "application/x-www-form-urlencoded" },
    body,
  });
  if (!response.ok) {
    const { message } = await extractResponseErrorPayload(response, DEFAULT_SIGN_OUT_ERROR);
    const retryable = response.status >= 500;
    throw new AuthClientError(retryable ? "auth_unavailable" : "request_error", message, { retryable });
  }
}

export async function registerWithCredentials(identifier: string, password: string, name?: string): Promise<void> {
  const normalizedIdentifier = normalizeIdentifier(identifier)?.value ?? identifier.trim();
  const response = await apiFetch("/api/auth/register", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ identifier: normalizedIdentifier, email: normalizedIdentifier, password, name }),
  });

  if (!response.ok) {
    const { message, code } = await extractResponseErrorPayload(response, DEFAULT_SIGN_UP_ERROR);
    if (response.status === 409) {
      throw new AuthClientError("registration_conflict", message);
    }
    if (response.status === 400) {
      throw new AuthClientError("validation_error", message);
    }
    if (response.status === 503 && code === "storage_unavailable") {
      throw new AuthClientError("storage_unavailable", message, { retryable: true });
    }
    const retryable = response.status >= 500;
    throw new AuthClientError(retryable ? "auth_unavailable" : "request_error", message, { retryable });
  }
}

export async function signInWithGoogle(): Promise<void> {
  const csrfToken = await getCsrfToken();
  const form = document.createElement("form");
  form.method = "POST";
  form.action = buildUrl("/api/auth/signin/google");
  form.style.display = "none";

  const addField = (name: string, value: string) => {
    const input = document.createElement("input");
    input.type = "hidden";
    input.name = name;
    input.value = value;
    form.appendChild(input);
  };

  addField("csrfToken", csrfToken);
  addField("callbackUrl", window.location.origin);

  document.body.appendChild(form);
  form.submit();
}

import React, { Suspense, lazy, useState, useEffect, useRef } from 'react';
import { Screen, DataPoint, ContributionMode } from './types';
import { getSession, signOut } from './lib/client/auth';
import { flushOfflineQueue } from './lib/client/offlineQueue';
import { sendSubmissionPayload } from './lib/client/submissionSync';
import Splash from './components/Screens/Splash';
import Home from './components/Screens/Home';
import Navigation from './components/Navigation';
import ErrorBoundary from './components/ErrorBoundary';

const Details = lazy(() => import('./components/Screens/Details'));
const Auth = lazy(() => import('./components/Screens/Auth'));
const ContributionFlow = lazy(() => import('./components/Screens/ContributionFlow'));
const Profile = lazy(() => import('./components/Screens/Profile'));
const Analytics = lazy(() => import('./components/Screens/Analytics'));
const Settings = lazy(() => import('./components/Screens/Settings'));
const QualityInfo = lazy(() => import('./components/Screens/QualityInfo'));
const RewardsCatalog = lazy(() => import('./components/Screens/RewardsCatalog'));
const AdminQueue = lazy(() => import('./components/Screens/AdminQueue'));
const DeltaDashboard = lazy(() => import('./components/Screens/DeltaDashboard'));

interface WindowWithIdleCallback extends Window {
  requestIdleCallback?: (callback: IdleRequestCallback, options?: IdleRequestOptions) => number;
  cancelIdleCallback?: (handle: number) => void;
}

const App: React.FC = () => {
  const isSyncingRef = useRef(false);
  const [currentScreen, setCurrentScreen] = useState<Screen>(Screen.SPLASH);
  const [selectedPoint, setSelectedPoint] = useState<DataPoint | null>(null);
  const [isOffline, setIsOffline] = useState(false);
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [isAdmin, setIsAdmin] = useState(false);
  const [language, setLanguage] = useState<'en' | 'fr'>(() => {
    const saved = localStorage.getItem('adl_language');
    return saved === 'en' ? 'en' : 'fr';
  });
  const [history, setHistory] = useState<Screen[]>([]);
  const [authReturnScreen, setAuthReturnScreen] = useState<Screen>(Screen.SPLASH);
  const [contributionMode, setContributionMode] = useState<ContributionMode>('CREATE');
  const [contributionPoint, setContributionPoint] = useState<DataPoint | null>(null);
  const t = (en: string, fr: string) => (language === 'fr' ? fr : en);

  const navigateTo = (screen: Screen, point: DataPoint | null = null) => {
    if (currentScreen === Screen.SPLASH && screen !== Screen.SPLASH) {
      localStorage.setItem("adl_splash_seen", "true");
    }
    if (screen === Screen.AUTH) {
      setAuthReturnScreen(currentScreen);
    }
    setHistory(prev => [...prev, currentScreen]);
    setCurrentScreen(screen);
    if (point) setSelectedPoint(point);
  };

  const goBack = () => {
    if (history.length > 0) {
      const prev = history[history.length - 1];
      setHistory(prevHistory => prevHistory.slice(0, -1));
      setCurrentScreen(prev);
      return;
    }
    if (currentScreen === Screen.AUTH) {
      setCurrentScreen(authReturnScreen);
      return;
    }
    // Fallback for screens opened via tab navigation (no history).
    setHistory([]);
    setCurrentScreen(Screen.HOME);
  };

  const switchTab = (screen: Screen) => {
    setHistory([]);
    if (screen === Screen.CONTRIBUTE && !isAuthenticated) {
      setAuthReturnScreen(currentScreen);
      setCurrentScreen(Screen.AUTH);
    } else {
      if (screen === Screen.AUTH) {
        setAuthReturnScreen(currentScreen);
      }
      if (screen === Screen.CONTRIBUTE) {
        setContributionMode('CREATE');
        setContributionPoint(null);
      }
      setCurrentScreen(screen);
    }
  };

  const openContribution = (mode: ContributionMode, point: DataPoint | null = null) => {
    setContributionMode(mode);
    setContributionPoint(point);
    if (isAuthenticated) {
      navigateTo(Screen.CONTRIBUTE);
      return;
    }
    navigateTo(Screen.AUTH);
  };

  useEffect(() => {
    localStorage.setItem('adl_language', language);
    document.documentElement.lang = language;
  }, [language]);

  useEffect(() => {
    const handleStatus = async () => {
      const online = navigator.onLine;
      setIsOffline(!online);
      if (online) {
        const runSync = async () => {
          if (isSyncingRef.current) return;
          isSyncingRef.current = true;
          try {
            await flushOfflineQueue(sendSubmissionPayload);
          } catch (error) {
            console.error('[App] Offline queue sync failed:', error);
          } finally {
            isSyncingRef.current = false;
          }
        };
        const windowWithIdle = window as WindowWithIdleCallback;
        if (typeof windowWithIdle.requestIdleCallback === 'function') {
          windowWithIdle.requestIdleCallback(() => {
            void runSync();
          }, { timeout: 2000 });
        } else {
          window.setTimeout(() => {
            void runSync();
          }, 0);
        }
      }
    };
    window.addEventListener('online', handleStatus);
    window.addEventListener('offline', handleStatus);
    void handleStatus();
    return () => {
      window.removeEventListener('online', handleStatus);
      window.removeEventListener('offline', handleStatus);
    };
  }, []);

  const refreshSession = async () => {
    const session = await getSession();
    const hasUser = !!session?.user;
    setIsAuthenticated(hasUser);
    setIsAdmin(Boolean(session?.user?.isAdmin));
    return hasUser;
  };

  useEffect(() => {
    const bootstrap = async () => {
      const hasUser = await refreshSession();
      const hasSeenSplash = localStorage.getItem("adl_splash_seen") === "true";
      if (currentScreen === Screen.SPLASH && (hasUser || hasSeenSplash)) {
        setHistory([]);
        setCurrentScreen(Screen.HOME);
      }
    };
    bootstrap();
  }, []);

  useEffect(() => {
    const hasSeenSplash = localStorage.getItem("adl_splash_seen") === "true";
    if (currentScreen === Screen.SPLASH && hasSeenSplash) {
      setHistory([]);
      setCurrentScreen(Screen.HOME);
    }
  }, [currentScreen]);

  const renderScreen = () => {
    switch (currentScreen) {
      case Screen.SPLASH:
        return <Splash onStart={(scr) => navigateTo(scr)} language={language} />;
      case Screen.HOME:
        return (
          <Home
            onSelectPoint={(p) => navigateTo(Screen.DETAILS, p)}
            isAuthenticated={isAuthenticated}
            isAdmin={isAdmin}
            onAuth={() => navigateTo(Screen.AUTH)}
            onContribute={() => openContribution('CREATE')}
            onProfile={() => switchTab(Screen.PROFILE)}
            language={language}
          />
        );
      case Screen.DETAILS:
        return (
          <Details
            point={selectedPoint}
            onBack={goBack}
            onEnrich={() => openContribution('ENRICH', selectedPoint)}
            onAddNew={() => openContribution('CREATE')}
            isAuthenticated={isAuthenticated}
            onAuth={() => navigateTo(Screen.AUTH)}
            language={language}
          />
        );
      case Screen.AUTH:
        return <Auth language={language} onBack={goBack} onComplete={async () => { await refreshSession(); switchTab(Screen.HOME); }} />;
      case Screen.CONTRIBUTE:
        return (
          <ContributionFlow
            language={language}
            onBack={goBack}
            onComplete={() => switchTab(Screen.HOME)}
            mode={contributionMode}
            seedPoint={contributionPoint}
          />
        );
      case Screen.PROFILE:
        return <Profile language={language} onBack={goBack} onSettings={() => navigateTo(Screen.SETTINGS)} onRedeem={() => navigateTo(Screen.REWARDS)} />;
      case Screen.ANALYTICS:
        return (
          <Analytics
            onBack={goBack}
            isAdmin={isAdmin}
            onAdmin={isAdmin ? () => navigateTo(Screen.ADMIN) : undefined}
            onDeltaDashboard={isAdmin ? () => navigateTo(Screen.DELTA_DASHBOARD) : undefined}
            language={language}
          />
        );
      case Screen.SETTINGS:
        return (
          <Settings
            onBack={goBack}
            language={language}
            onLanguageChange={setLanguage}
            onLogout={async () => {
              try {
                await signOut();
              } catch {
                // Fallback to local logout even if server sign-out fails.
              } finally {
                await refreshSession();
                setIsAuthenticated(false);
                switchTab(Screen.SPLASH);
              }
            }}
          />
        );
      case Screen.QUALITY:
        return <QualityInfo language={language} onBack={goBack} />;
      case Screen.REWARDS:
        return <RewardsCatalog language={language} onBack={goBack} />;
      case Screen.ADMIN:
        return <AdminQueue language={language} onBack={goBack} />;
      case Screen.DELTA_DASHBOARD:
        return <DeltaDashboard language={language} onBack={goBack} />;
      default:
        return <Splash onStart={(scr) => navigateTo(scr)} language={language} />;
    }
  };

  return (
    <ErrorBoundary>
    <div className="app-shell flex flex-col w-full max-w-md mx-auto bg-white shadow-2xl relative overflow-hidden border-x border-gray-100">
      {isOffline && (
        <div className="bg-amber-600 text-white text-[10px] font-bold py-1.5 px-4 text-center z-50 tracking-widest uppercase">
          {t('Offline Mode • Local Sync Active', 'Mode hors ligne • Sync locale active')}
        </div>
      )}

      <main className="flex-1 overflow-hidden relative">
        <Suspense
          fallback={
            <div className="h-full w-full bg-[#f9fafb] p-4">
              <div className="bg-white p-4 rounded-2xl border border-gray-100 shadow-sm text-xs text-gray-500">
                {t('Loading screen...', 'Chargement de l\'ecran...')}
              </div>
            </div>
          }
        >
          {renderScreen()}
        </Suspense>
      </main>

      {!([Screen.SPLASH, Screen.AUTH, Screen.CONTRIBUTE].includes(currentScreen)) && (
        <Navigation
          currentScreen={currentScreen}
          onNavigate={(scr) => switchTab(scr)}
          isAuthenticated={isAuthenticated}
          isAdmin={isAdmin}
          language={language}
        />
      )}
    </div>
    </ErrorBoundary>
  );
};

export default App;

