  2→import React, { Suspense, lazy, useState, useEffect, useRef } from 'react';
  3→import { Screen, DataPoint, ContributionMode } from './types';
  4→import { getSession, signOut } from './lib/client/auth';
  5→import { flushOfflineQueue } from './lib/client/offlineQueue';
  6→import { sendSubmissionPayload } from './lib/client/submissionSync';
  7→import Splash from './components/Screens/Splash';
  8→import Home from './components/Screens/Home';
  9→import Navigation from './components/Navigation';
 10→import ErrorBoundary from './components/ErrorBoundary';
 11→
 12→const Details = lazy(() => import('./components/Screens/Details'));
 13→const Auth = lazy(() => import('./components/Screens/Auth'));
 14→const ContributionFlow = lazy(() => import('./components/Screens/ContributionFlow'));
 15→const Profile = lazy(() => import('./components/Screens/Profile'));
 16→const Analytics = lazy(() => import('./components/Screens/Analytics'));
 17→const Settings = lazy(() => import('./components/Screens/Settings'));
 18→const QualityInfo = lazy(() => import('./components/Screens/QualityInfo'));
 19→const RewardsCatalog = lazy(() => import('./components/Screens/RewardsCatalog'));
 20→const AdminQueue = lazy(() => import('./components/Screens/AdminQueue'));
 21→const DeltaDashboard = lazy(() => import('./components/Screens/DeltaDashboard'));
 22→
 23→interface WindowWithIdleCallback extends Window {
 24→  requestIdleCallback?: (callback: IdleRequestCallback, options?: IdleRequestOptions) => number;
 25→  cancelIdleCallback?: (handle: number) => void;
 26→}
 27→
 28→const App: React.FC = () => {
 29→  const isSyncingRef = useRef(false);
 30→  const [currentScreen, setCurrentScreen] = useState<Screen>(Screen.SPLASH);
 31→  const [selectedPoint, setSelectedPoint] = useState<DataPoint | null>(null);
 32→  const [isOffline, setIsOffline] = useState(false);
 33→  const [isAuthenticated, setIsAuthenticated] = useState(false);
 34→  const [isAdmin, setIsAdmin] = useState(false);
 35→  const [userRole, setUserRole] = useState<'agent' | 'admin' | 'client'>('agent');
 36→  const [language, setLanguage] = useState<'en' | 'fr'>(() => {
 37→    const saved = localStorage.getItem('adl_language');
 38→    return saved === 'en' ? 'en' : 'fr';
 39→  });
 40→  const [history, setHistory] = useState<Screen[]>([]);
 41→  const [authReturnScreen, setAuthReturnScreen] = useState<Screen>(Screen.SPLASH);
 42→  const [contributionMode, setContributionMode] = useState<ContributionMode>('CREATE');
 43→  const [contributionPoint, setContributionPoint] = useState<DataPoint | null>(null);
 44→  const t = (en: string, fr: string) => (language === 'fr' ? fr : en);
 45→
 46→  const navigateTo = (screen: Screen, point: DataPoint | null = null) => {
 47→    if (currentScreen === Screen.SPLASH && screen !== Screen.SPLASH) {
 48→      localStorage.setItem("adl_splash_seen", "true");
 49→    }
 50→    if (screen === Screen.AUTH) {
 51→      setAuthReturnScreen(currentScreen);
 52→    }
 53→    setHistory(prev => [...prev, currentScreen]);
 54→    setCurrentScreen(screen);
 55→    if (point) setSelectedPoint(point);
 56→  };
 57→
 58→  const goBack = () => {
 59→    if (history.length > 0) {
 60→      const prev = history[history.length - 1];
 61→      setHistory(prevHistory => prevHistory.slice(0, -1));
 62→      setCurrentScreen(prev);
 63→      return;
 64→    }
 65→    if (currentScreen === Screen.AUTH) {
 66→      setCurrentScreen(authReturnScreen);
 67→      return;
 68→    }
 69→    // Fallback for screens opened via tab navigation (no history).
 70→    setHistory([]);
 71→    setCurrentScreen(Screen.HOME);
 72→  };
 73→
 74→  const isClient = userRole === 'client';
 75→
 76→  const switchTab = (screen: Screen) => {
 77→    setHistory([]);
 78→    // Clients cannot access the capture flow
 79→    if (screen === Screen.CONTRIBUTE && isClient) {
 80→      return;
 81→    }
 82→    if (screen === Screen.CONTRIBUTE && !isAuthenticated) {
 83→      setAuthReturnScreen(currentScreen);
 84→      setCurrentScreen(Screen.AUTH);
 85→    } else {
 86→      if (screen === Screen.AUTH) {
 87→        setAuthReturnScreen(currentScreen);
 88→      }
 89→      if (screen === Screen.CONTRIBUTE) {
 90→        setContributionMode('CREATE');
 91→        setContributionPoint(null);
 92→      }
 93→      setCurrentScreen(screen);
 94→    }
 95→  };
 96→
 97→  const openContribution = (mode: ContributionMode, point: DataPoint | null = null) => {
 98→    setContributionMode(mode);
 99→    setContributionPoint(point);
100→    if (isAuthenticated) {
101→      navigateTo(Screen.CONTRIBUTE);
102→      return;
103→    }
104→    navigateTo(Screen.AUTH);
105→  };
106→
107→  useEffect(() => {
108→    localStorage.setItem('adl_language', language);
109→    document.documentElement.lang = language;
110→  }, [language]);
111→
112→  useEffect(() => {
113→    const handleStatus = async () => {
114→      const online = navigator.onLine;
115→      setIsOffline(!online);
116→      if (online) {
117→        const runSync = async () => {
118→          if (isSyncingRef.current) return;
119→          isSyncingRef.current = true;
120→          try {
121→            await flushOfflineQueue(sendSubmissionPayload);
122→          } catch (error) {
123→            console.error('[App] Offline queue sync failed:', error);
124→          } finally {
125→            isSyncingRef.current = false;
126→          }
127→        };
128→        const windowWithIdle = window as WindowWithIdleCallback;
129→        if (typeof windowWithIdle.requestIdleCallback === 'function') {
130→          windowWithIdle.requestIdleCallback(() => {
131→            void runSync();
132→          }, { timeout: 2000 });
133→        } else {
134→          window.setTimeout(() => {
135→            void runSync();
136→          }, 0);
137→        }
138→      }
139→    };
140→    window.addEventListener('online', handleStatus);
141→    window.addEventListener('offline', handleStatus);
142→    void handleStatus();
143→    return () => {
144→      window.removeEventListener('online', handleStatus);
145→      window.removeEventListener('offline', handleStatus);
146→    };
147→  }, []);
148→
149→  const refreshSession = async () => {
150→    const session = await getSession();
151→    const hasUser = !!session?.user;
152→    setIsAuthenticated(hasUser);
153→    setIsAdmin(Boolean(session?.user?.isAdmin));
154→    setUserRole((session?.user?.role as 'agent' | 'admin' | 'client') ?? 'agent');
155→    return hasUser;
156→  };
157→
158→  useEffect(() => {
159→    const bootstrap = async () => {
160→      const hasUser = await refreshSession();
161→      const hasSeenSplash = localStorage.getItem("adl_splash_seen") === "true";
162→      if (currentScreen === Screen.SPLASH && (hasUser || hasSeenSplash)) {
163→        setHistory([]);
164→        const session = await getSession();
165→        const role = (session?.user?.role as 'agent' | 'admin' | 'client') ?? 'agent';
166→        setCurrentScreen(role === 'client' ? Screen.DELTA_DASHBOARD : Screen.HOME);
167→      }
168→    };
169→    bootstrap();
170→  }, []);
171→
172→  useEffect(() => {
173→    const hasSeenSplash = localStorage.getItem("adl_splash_seen") === "true";
174→    if (currentScreen === Screen.SPLASH && hasSeenSplash) {
175→      setHistory([]);
176→      setCurrentScreen(isClient ? Screen.DELTA_DASHBOARD : Screen.HOME);
177→    }
178→  }, [currentScreen, isClient]);
179→
180→  const renderScreen = () => {
181→    switch (currentScreen) {
182→      case Screen.SPLASH:
183→        return <Splash onStart={(scr) => navigateTo(scr)} language={language} />;
184→      case Screen.HOME:
185→        return (
186→          <Home
187→            onSelectPoint={(p) => navigateTo(Screen.DETAILS, p)}
188→            isAuthenticated={isAuthenticated}
189→            isAdmin={isAdmin}
190→            onAuth={() => navigateTo(Screen.AUTH)}
191→            onContribute={isClient ? undefined : () => openContribution('CREATE')}
192→            onProfile={() => switchTab(Screen.PROFILE)}
193→            language={language}
194→          />
195→        );
196→      case Screen.DETAILS:
197→        return (
198→          <Details
199→            point={selectedPoint}
200→            onBack={goBack}
201→            onEnrich={() => openContribution('ENRICH', selectedPoint)}
202→            onAddNew={() => openContribution('CREATE')}
203→            isAuthenticated={isAuthenticated}
204→            onAuth={() => navigateTo(Screen.AUTH)}
205→            language={language}
206→          />
207→        );
208→      case Screen.AUTH:
209→        return <Auth language={language} onBack={goBack} onComplete={async () => {
210→          await refreshSession();
211→          const session = await getSession();
212→          const role = (session?.user?.role as 'agent' | 'admin' | 'client') ?? 'agent';
213→          switchTab(role === 'client' ? Screen.DELTA_DASHBOARD : Screen.HOME);
214→        }} />;
215→      case Screen.CONTRIBUTE:
216→        return (
217→          <ContributionFlow
218→            language={language}
219→            onBack={goBack}
220→            onComplete={() => switchTab(Screen.HOME)}
221→            mode={contributionMode}
222→            seedPoint={contributionPoint}
223→          />
224→        );
225→      case Screen.PROFILE:
226→        return <Profile language={language} onBack={goBack} onSettings={() => navigateTo(Screen.SETTINGS)} onRedeem={() => navigateTo(Screen.REWARDS)} />;
227→      case Screen.ANALYTICS:
228→        return (
229→          <Analytics
230→            onBack={goBack}
231→            isAdmin={isAdmin}
232→            onAdmin={isAdmin ? () => navigateTo(Screen.ADMIN) : undefined}
233→            onDeltaDashboard={(isAdmin || isClient) ? () => navigateTo(Screen.DELTA_DASHBOARD) : undefined}
234→            language={language}
235→          />
236→        );
237→      case Screen.SETTINGS:
238→        return (
239→          <Settings
240→            onBack={goBack}
241→            language={language}
242→            onLanguageChange={setLanguage}
243→            onLogout={async () => {
244→              try {
245→                await signOut();
246→              } catch {
247→                // Fallback to local logout even if server sign-out fails.
248→              } finally {
249→                await refreshSession();
250→                setIsAuthenticated(false);
251→                switchTab(Screen.SPLASH);
252→              }
253→            }}
254→          />
255→        );
256→      case Screen.QUALITY:
257→        return <QualityInfo language={language} onBack={goBack} />;
258→      case Screen.REWARDS:
259→        return <RewardsCatalog language={language} onBack={goBack} />;
260→      case Screen.ADMIN:
261→        return <AdminQueue language={language} onBack={goBack} />;
262→      case Screen.DELTA_DASHBOARD:
263→        return <DeltaDashboard language={language} onBack={goBack} />;
264→      default:
265→        return <Splash onStart={(scr) => navigateTo(scr)} language={language} />;
266→    }
267→  };
268→
269→  return (
270→    <ErrorBoundary>
271→    <div className="app-shell flex flex-col w-full max-w-md mx-auto bg-white shadow-2xl relative overflow-hidden border-x border-gray-100">
272→      {isOffline && (
273→        <div className="bg-amber-600 text-white text-[10px] font-bold py-1.5 px-4 text-center z-50 tracking-widest uppercase">
274→          {t('Offline Mode • Local Sync Active', 'Mode hors ligne • Sync locale active')}
275→        </div>
276→      )}
